function StatItem({ value, label, loading }) {
  return (
    <div style={S.statItem}>
      <span style={S.statNum}>
        {loading ? '—' : typeof value === 'number' ? value.toLocaleString() : value}
      </span>
      <span style={S.statLabel}>{label}</span>
    </div>
  );
}

